"""Version metadata for git export-subst archive stamping.

The two module-level constants are populated at archive time by
``git archive --worktree-attributes`` when the top-level ``.gitattributes``
file marks this module with the ``export-subst`` attribute.  In a live
git checkout they retain their unexpanded ``$Format:…$`` placeholder
strings, which ``_get_git_version()`` in ``__init__.py`` uses as a signal
to fall back to ``git describe`` (Tier 2) or ``importlib.metadata`` (Tier 3).
"""

_GIT_ARCHIVE_HASH = "$Format:%H$"
_GIT_ARCHIVE_REF  = "$Format:%D$"    # decorated refs: "tag: v0.3, HEAD -> main"
